const items = $input.all();

// --- Extract RSI ---
const rsiItem = items.find(i => i.json.meta?.indicator?.name?.includes("RSI"));
const rsi = rsiItem ? Number(rsiItem.json.values[0].rsi) : null;

// --- Extract Price Data ---
const priceItem = items.find(i => i.json.symbol);
const price = priceItem ? Number(priceItem.json.close) : null;
const volume = priceItem ? Number(priceItem.json.volume) : null;
const avgVolume = priceItem ? Number(priceItem.json.average_volume) : null;

// --- Momentum Classification ---
let momentum = "UNKNOWN";
if (rsi !== null) {
  if (rsi < 30) momentum = "OVERSOLD";
  else if (rsi < 35) momentum = "NEAR_OVERSOLD";
  else if (rsi < 60) momentum = "NEUTRAL";
  else if (rsi < 70) momentum = "NEAR_OVERBOUGHT";
  else momentum = "OVERBOUGHT";
}

// --- Volume Signal ---
const volumeSignal =
  volume && avgVolume && volume > avgVolume
    ? "HIGH_VOLUME"
    : "NORMAL_VOLUME";

// --- Final Action ---
let action = "WAIT";
if (momentum === "OVERSOLD") action = "PREPARE_BUY";
else if (momentum === "NEAR_OVERSOLD") action = "WATCH";

// --- Output ---
return [{
  json: {
    symbol: priceItem.json.symbol,
    price,
    rsi,
    momentum,
    volume,
    avgVolume,
    volumeSignal,
    action
  }
}];

